import{c as n,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const p=JSON.parse('{"title":"Các loại kỳ thi trên hệ thống","description":"","frontmatter":{},"headers":[],"relativePath":"gioi-thieu/cac-loai-ky-thi.md","filePath":"gioi-thieu/cac-loai-ky-thi.md","lastUpdated":0}'),a={name:"gioi-thieu/cac-loai-ky-thi.md"};function r(g,t,c,l,e,u){return h(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="cac-loai-ky-thi-tren-he-thong" tabindex="-1">Các loại kỳ thi trên hệ thống <a class="header-anchor" href="#cac-loai-ky-thi-tren-he-thong" aria-label="Permalink to “Các loại kỳ thi trên hệ thống”">​</a></h1><p>Hệ thống LamSơn Edutech hỗ trợ nhiều loại kỳ thi và hình thức luyện tập. Phần này giúp bạn chọn đúng loại phù hợp với mục tiêu.</p><h2 id="_1-thi-đanh-gia-nang-luc-đgnl-hsa" tabindex="-1">1. Thi Đánh giá năng lực - ĐGNL (HSA) <a class="header-anchor" href="#_1-thi-đanh-gia-nang-luc-đgnl-hsa" aria-label="Permalink to “1. Thi Đánh giá năng lực - ĐGNL (HSA)”">​</a></h2><p><strong>Cơ quan tổ chức:</strong> Đại học Quốc gia Hà Nội (VNU).</p><p><strong>Cấu trúc đề:</strong> 3 phần, tổng cộng ~150 câu, 195 phút:</p><ul><li>Phần 1: <strong>Tư duy định lượng (Toán)</strong> - 50 câu / 75 phút</li><li>Phần 2: <strong>Tư duy định tính (Ngữ văn - Ngôn ngữ)</strong> - 50 câu / 60 phút</li><li>Phần 3: <strong>Khoa học (Tự nhiên + Xã hội)</strong> - 50 câu / 60 phút</li></ul><p><strong>Đặc điểm trên hệ thống:</strong></p><ul><li>Đề thi đa dạng dạng câu hỏi: trắc nghiệm A/B/C/D, điền số, kéo thả.</li><li>Có <strong>đồng hồ đếm ngược</strong> theo từng phần.</li><li>Khi hết giờ một phần, hệ thống tự chuyển sang phần kế tiếp.</li><li>Chấm điểm theo thang điểm chuẩn của ĐHQGHN.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/thi-dgnl-hsa">Thi ĐGNL (HSA)</a></p><h2 id="_2-thi-đanh-gia-tu-duy-đgtd-tsa" tabindex="-1">2. Thi Đánh giá tư duy - ĐGTD (TSA) <a class="header-anchor" href="#_2-thi-đanh-gia-tu-duy-đgtd-tsa" aria-label="Permalink to “2. Thi Đánh giá tư duy - ĐGTD (TSA)”">​</a></h2><p><strong>Cơ quan tổ chức:</strong> Đại học Bách Khoa Hà Nội (HUST).</p><p><strong>Cấu trúc đề:</strong> 3 phần, ~150 phút:</p><ul><li><strong>Tư duy Toán học</strong></li><li><strong>Tư duy Đọc hiểu</strong></li><li><strong>Tư duy Khoa học / Giải quyết vấn đề</strong></li></ul><p><strong>Đặc điểm trên hệ thống:</strong></p><ul><li>Có dạng đề thi online riêng cho ĐGTD (route <code>https://lamsonedutech.vn/luyen-tap/lam-kiem-tra-online-dgtd/...</code>).</li><li>Dạng câu hỏi: trắc nghiệm 1 đáp án, nhiều đáp án, đúng/sai, điền đáp án.</li><li>Hệ thống chấm tự động và đưa ra phân tích điểm theo từng phần.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/thi-dgtd-tsa">Thi ĐGTD (TSA)</a></p><h2 id="_3-thi-thu-tot-nghiep-thpt" tabindex="-1">3. Thi thử Tốt nghiệp THPT <a class="header-anchor" href="#_3-thi-thu-tot-nghiep-thpt" aria-label="Permalink to “3. Thi thử Tốt nghiệp THPT”">​</a></h2><p><strong>Mục tiêu:</strong> Mô phỏng kỳ thi tốt nghiệp THPT do Bộ GD&amp;ĐT tổ chức.</p><p><strong>Môn thi hỗ trợ:</strong> Toán, Ngữ văn, Vật Lí, Hóa học, Sinh học, Lịch sử, Địa lí, (Ngoại ngữ tùy đợt).</p><p><strong>Đặc điểm trên hệ thống:</strong></p><ul><li>Định dạng đề bám sát đề minh họa của Bộ.</li><li>Cho làm theo từng môn riêng lẻ hoặc theo tổ hợp (KHTN/KHXH).</li><li>Có khả năng so sánh kết quả với điểm chuẩn các năm.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/thi-tnthpt">Thi thử Tốt nghiệp THPT</a></p><h2 id="_4-kiem-tra-đau-vao" tabindex="-1">4. Kiểm tra đầu vào <a class="header-anchor" href="#_4-kiem-tra-đau-vao" aria-label="Permalink to “4. Kiểm tra đầu vào”">​</a></h2><p><strong>Mục tiêu:</strong> Đánh giá trình độ học viên trước khi bắt đầu một khóa học hoặc lộ trình.</p><p><strong>Đặc điểm:</strong></p><ul><li>Đề ngắn (15-45 phút), tập trung kiến thức nền tảng.</li><li>Kết quả giúp <strong>gợi ý chuyên đề cần học</strong> và <strong>mức xuất phát</strong> trong khóa.</li><li>Học viên có thể làm lại nếu giáo viên cho phép.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/kiem-tra-dau-vao">Kiểm tra đầu vào</a></p><h2 id="_5-luyen-tap-theo-chuyen-đe-module" tabindex="-1">5. Luyện tập theo chuyên đề / Module <a class="header-anchor" href="#_5-luyen-tap-theo-chuyen-đe-module" aria-label="Permalink to “5. Luyện tập theo chuyên đề / Module”">​</a></h2><p><strong>Mục tiêu:</strong> Học sâu từng chuyên đề trong khóa.</p><p><strong>Đặc điểm:</strong></p><ul><li>Mỗi chuyên đề có <strong>bài giảng + bài luyện tập + bài kiểm tra cuối chuyên đề</strong>.</li><li>Không giới hạn số lần làm bài (nếu cấu hình cho phép).</li><li>Có hiển thị <strong>đáp án và lời giải</strong> ngay sau khi nộp.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/luyen-tap">Luyện tập theo chuyên đề</a></p><h2 id="_6-bo-đe-thi" tabindex="-1">6. Bộ đề thi <a class="header-anchor" href="#_6-bo-đe-thi" aria-label="Permalink to “6. Bộ đề thi”">​</a></h2><p><strong>Mục tiêu:</strong> Luyện theo bộ đề (vd: 10 đề HSA chọn lọc, 20 đề Toán THPT).</p><p><strong>Đặc điểm:</strong></p><ul><li>Mỗi bộ đề có nhiều đề thành phần.</li><li>Có thể theo dõi tiến độ &quot;đã làm bao nhiêu đề&quot;.</li><li>Sau khi làm xong cả bộ, hệ thống xếp hạng trong nhóm học viên cùng bộ đề.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/bo-de-thi">Bộ đề thi</a></p><h2 id="_7-hoc-lieu-giao-trinh" tabindex="-1">7. Học liệu / Giáo trình <a class="header-anchor" href="#_7-hoc-lieu-giao-trinh" aria-label="Permalink to “7. Học liệu / Giáo trình”">​</a></h2><p><strong>Mục tiêu:</strong> Cung cấp tài liệu đọc/tham khảo.</p><p><strong>Đặc điểm:</strong></p><ul><li>Sách PDF, video bài giảng dài, file slide.</li><li>Có thể tải về (nếu cấu hình cho phép) hoặc đọc online.</li></ul><p>→ Xem hướng dẫn: <a href="/hoc-vien/hoc-lieu">Học liệu</a></p><h2 id="toi-nen-chon-loai-nao" tabindex="-1">Tôi nên chọn loại nào? <a class="header-anchor" href="#toi-nen-chon-loai-nao" aria-label="Permalink to “Tôi nên chọn loại nào?”">​</a></h2><table tabindex="0"><thead><tr><th>Mục tiêu của bạn</th><th>Loại nên dùng</th></tr></thead><tbody><tr><td>Thi đại học vào ĐHQG Hà Nội</td><td><strong>ĐGNL (HSA)</strong> + Luyện tập chuyên đề</td></tr><tr><td>Thi đại học vào ĐH Bách Khoa, ĐH Kinh tế Quốc dân…</td><td><strong>ĐGTD (TSA)</strong> + Luyện tập chuyên đề</td></tr><tr><td>Thi tốt nghiệp THPT</td><td><strong>Thi thử TNTHPT</strong> từng môn</td></tr><tr><td>Mới bắt đầu, chưa biết trình độ</td><td><strong>Kiểm tra đầu vào</strong> trước</td></tr><tr><td>Học từng chủ đề kỹ một</td><td><strong>Luyện tập theo chuyên đề</strong></td></tr><tr><td>Luyện đề tập trung</td><td><strong>Bộ đề thi</strong></td></tr><tr><td>Tự đọc, tham khảo</td><td><strong>Học liệu / Giáo trình</strong></td></tr></tbody></table>',44)])])}const d=n(a,[["render",r]]);export{p as __pageData,d as default};
